Rules.InvariantScript:
If(
    Not(IsBlank(CurrentReviewItem)),
    UpdateContext({currentitempatientid: "for " & CurrentReviewItem.'Patient UID'}),
    UpdateContext({currentitempatientid: " (New Item)"});

);
If(
    Not(IsBlankOrError(Param("entity"))),
    Set(CurrentReviewItem,LookUp('UK Customs SharePoint Case Intake Review Form',ID = Int(Param("id"))));
    UpdateContext({currentitempatientid: "for " & CurrentReviewItem.'Patient UID'}),
    Notify(
        "Loading review item..." & CurrentReviewItem.'Patient UID',
        NotificationType.Information,
        2000
    )
);
UpdateContext({isupdating:false});
